#include <stdio.h>
#include <stdint.h>

#define MOD1 1000000007LL
#define MOD2 1000000009LL

long long modpow(long long a, long long e, long long mod) {
    long long res = 1 % mod;
    a %= mod;
    if (a < 0) a += mod;
    while (e > 0) {
        if (e & 1) res = (__int128)res * a % mod;
        a = (__int128)a * a % mod;
        e >>= 1;
    }
    return res;
}

long long compute_mod(unsigned long long N, long long MOD) {
    if (N == 1) return 0;

    long long nmod = (long long)(N % MOD);
    long long nm1 = (long long)((N - 1ULL) % MOD);

    long long num = (__int128)nmod * nm1 % MOD;

    long long twoNminus3 = (2LL * nmod - 3 + MOD) % MOD;
    long long denom = (2LL * twoNminus3) % MOD;

    long long inv = modpow(denom, MOD - 2, MOD);

    return (long long)((__int128)num * inv % MOD);
}

int main() {
    int T;
    scanf("%d", &T);

    while (T--) {
        unsigned long long N;
        scanf("%llu", &N);

        long long ans1 = compute_mod(N, MOD1);
        long long ans2 = compute_mod(N, MOD2);

        printf("%lld %lld\n", ans1, ans2);
    }

    return 0;
}

