import java.util.Scanner;

public class Main {
    static final long MOD1 = 1000000007L;
    static final long MOD2 = 1000000009L;

    public static long modpow(long a, long e, long mod) {
        long res = 1 % mod;
        a %= mod;
        if (a < 0) a += mod;
        while (e > 0) {
            if (e % 2 == 1) res = (res * a) % mod;
            a = (a * a) % mod;
            e >>= 1;
        }
        return res;
    }

    public static long compute_mod(long N, long MOD) {
        if (N == 1) return 0;

        long nmod = N % MOD;
        long nm1 = (N - 1) % MOD;

        long num = (nmod * nm1) % MOD;

        long twoNminus3 = (2 * nmod - 3 + MOD) % MOD;
        long denom = (2 * twoNminus3) % MOD;

        long inv = modpow(denom, MOD - 2, MOD);

        return (num * inv) % MOD;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();

        while (T-- > 0) {
            long N = scanner.nextLong();

            long ans1 = compute_mod(N, MOD1);
            long ans2 = compute_mod(N, MOD2);

            System.out.println(ans1 + " " + ans2);
        }
    }
}

