const fs = require('fs');
const lines = fs.readFileSync(0, 'utf-8').trim().split('\n');
let idx = 0;

const MOD1 = 1000000007n;
const MOD2 = 1000000009n;

function modpow(a, e, mod) {
    let res = 1n % mod;
    a = a % mod;
    if (a < 0) a += mod;
    while (e > 0) {
        if (e & 1n) res = (res * a) % mod;
        a = (a * a) % mod;
        e >>= 1n;
    }
    return res;
}

function compute_mod(N, MOD) {
    if (N === 1n) return 0n;

    let nmod = N % MOD;
    let nm1 = (N - 1n) % MOD;

    let num = (nmod * nm1) % MOD;

    let twoNminus3 = (2n * nmod - 3n + MOD) % MOD;
    let denom = (2n * twoNminus3) % MOD;

    let inv = modpow(denom, MOD - 2n, MOD);

    return (num * inv) % MOD;
}

let T = parseInt(lines[idx++]);

while (T-- > 0) {
    let N = BigInt(lines[idx++]);

    let ans1 = compute_mod(N, MOD1);
    let ans2 = compute_mod(N, MOD2);

    console.log(ans1.toString() + ' ' + ans2.toString());
